     1→/**
     2→ * TabbedSidebarLayout Component
     3→ *
     4→ * Notion-inspired tab-based sidebar layout for Notes page.
     5→ * Layout: Tabbed Sidebar | Editor
     6→ *
     7→ * Features:
     8→ * - Single sidebar with tabs (Folders, Tags, All Notes)
     9→ * - Each tab shows different navigation view
    10→ * - Compact, efficient use of space
    11→ * - Editor fills remaining space (full height)
    12→ * - Quick switching between navigation modes
    13→ */
    14→
    15→import React, { useCallback, useMemo, useRef, useState } from 'react';
    16→import { motion, AnimatePresence } from 'framer-motion';
    17→import {
    18→  Folder as FolderIcon,
    19→  Tag,
    20→  FileText,
    21→  PanelLeftClose,
    22→  PanelLeftOpen,
    23→  Search,
    24→  Settings2,
    25→  Plus,
    26→  Star,
    27→  Pin,
    28→  X,
    29→  ChevronDown,
    30→  ChevronRight,
    31→  FolderOpen,
    32→} from 'lucide-react';
    33→import { useSettingsStore } from '../../stores/useSettingsStore';
    34→import { useFoldersStore } from '../../stores/useFoldersStore';
    35→import { useNotesStore } from '../../stores/useNotesStore';
    36→import type { Folder, Note } from '../../types/notes';
    37→import { SidebarResizer } from './SidebarResizer';
    38→import { useTags, useTagCounts } from '../../hooks/useTags';
    39→import { useReducedMotion } from '../../hooks/useReducedMotion';
    40→
    41→type SidebarTab = 'folders' | 'tags' | 'all';
    42→
    43→export interface TabbedSidebarLayoutProps {
    44→  /** Content to render in the editor pane */
    45→  children: React.ReactNode;
    46→  /** Active tag filters */
    47→  activeTags: string[];
    48→  /** Callback to add a tag filter */
    49→  onAddTag: (tag: string) => void;
    50→  /** Callback to remove a tag filter */
    51→  onRemoveTag: (tag: string) => void;
    52→  /** Callback to clear all tag filters */
    53→  onClearAllTags: () => void;
    54→  /** Callback to open tag manager modal */
    55→  onOpenTagManager: () => void;
    56→  /** Callback to open template library modal */
    57→  onOpenTemplateLibrary: () => void;
    58→  /** Callback to open export modal */
    59→  onOpenExportModal: () => void;
    60→  /** Callback to open layout settings */
    61→  onOpenLayoutSettings?: () => void;
    62→}
    63→
    64→// Animation variants for folder children
    65→const getChildrenVariants = (reduceMotion: boolean) => ({
    66→  hidden: {
    67→    opacity: reduceMotion ? 1 : 0,
    68→    height: 0,
    69→    transition: { duration: reduceMotion ? 0 : 0.15, ease: 'easeInOut' as const },
    70→  },
    71→  visible: {
    72→    opacity: 1,
    73→    height: 'auto',
    74→    transition: { duration: reduceMotion ? 0 : 0.15, ease: 'easeInOut' as const },
    75→  },
    76→});
    77→
    78→export const TabbedSidebarLayout: React.FC<TabbedSidebarLayoutProps> = ({
    79→  children,
    80→  activeTags,
    81→  onAddTag,
    82→  onRemoveTag,
    83→  onOpenTagManager,
    84→  onOpenLayoutSettings,
    85→}) => {
    86→  const sidebarRef = useRef<HTMLDivElement>(null);
    87→  const prefersReducedMotion = useReducedMotion();
    88→
    89→  // Sidebar state
    90→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
    91→  const [activeTab, setActiveTab] = useState<SidebarTab>('folders');
    92→  const [searchQuery, setSearchQuery] = useState('');
    93→  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set());
    94→
    95→  // Get layout preferences
    96→  const notesLayout = useSettingsStore((state) => state.notesLayout);
    97→  const setNotesLayout = useSettingsStore((state) => state.setNotesLayout);
    98→  const { sidebarWidth } = notesLayout;
    99→
   100→  // Get folders and notes
   101→  const foldersObj = useFoldersStore((state) => state.folders);
   102→  const setActiveFolder = useFoldersStore((state) => state.setActiveFolder);
   103→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   104→  const notesObj = useNotesStore((state) => state.notes);
   105→  const activeNoteId = useNotesStore((state) => state.activeNoteId);
   106→  const setActiveNote = useNotesStore((state) => state.setActiveNote);
   107→  const createNote = useNotesStore((state) => state.createNote);
   108→
   109→  // Get tags
   110→  const allTags = useTags();
   111→  const tagCountsArray = useTagCounts();
   112→
   113→  // Convert objects to arrays
   114→  const notes = useMemo(() => Object.values(notesObj), [notesObj]);
   115→  const folders = useMemo(() => Object.values(foldersObj), [foldersObj]);
   116→
   117→  // Convert tag counts array to a lookup map
   118→  const tagCounts = useMemo(
   119→    () =>
   120→      tagCountsArray.reduce((acc, { tag, count }) => {
   121→        acc[tag] = count;
   122→        return acc;
   123→      }, {} as Record<string, number>),
   124→    [tagCountsArray]
   125→  );
   126→
   127→  // Filter notes by search query and active tags
   128→  const filteredNotes = useMemo(() => {
   129→    let result = notes;
   130→
   131→    // Filter by search query
   132→    if (searchQuery.trim()) {
   133→      const query = searchQuery.toLowerCase();
   134→      result = result.filter(
   135→        (note) =>
   136→          note.title.toLowerCase().includes(query) ||
   137→          note.content.toLowerCase().includes(query)
   138→      );
   139→    }
   140→
   141→    // Filter by active tags
   142→    if (activeTags.length > 0) {
   143→      result = result.filter((note) =>
   144→        activeTags.every((tag) => note.tags.includes(tag))
   145→      );
   146→    }
   147→
   148→    // Filter by active folder (if in folders tab)
   149→    if (activeTab === 'folders' && activeFolderId !== null) {
   150→      result = result.filter((n) => n.folderId === activeFolderId);
   151→    }
   152→
   153→    // Sort by updated date (most recent first)
   154→    return result.sort(
   155→      (a, b) => b.updatedAt.getTime() - a.updatedAt.getTime()
   156→    );
   157→  }, [notes, searchQuery, activeTags, activeTab, activeFolderId]);
   158→
   159→  // Get root folders
   160→  const rootFolders = useMemo(
   161→    () => folders.filter((f) => f.parentId === null),
   162→    [folders]
   163→  );
   164→
   165→  // Get child folders
   166→  const getChildFolders = useCallback(
   167→    (parentId: string | null): Folder[] => {
   168→      return folders.filter((f) => f.parentId === parentId);
   169→    },
   170→    [folders]
   171→  );
   172→
   173→  // Handle folder toggle
   174→  const toggleFolder = useCallback((folderId: string) => {
   175→    setExpandedFolders((prev) => {
   176→      const next = new Set(prev);
   177→      if (next.has(folderId)) {
   178→        next.delete(folderId);
   179→      } else {
   180→        next.add(folderId);
   181→      }
   182→      return next;
   183→    });
   184→  }, []);
   185→
   186→  // Handle folder selection
   187→  const handleSelectFolder = useCallback(
   188→    (folderId: string | null) => {
   189→      setActiveFolder(folderId);
   190→    },
   191→    [setActiveFolder]
   192→  );
   193→
   194→  // Handle note selection
   195→  const handleSelectNote = useCallback(
   196→    (noteId: string) => {
   197→      setActiveNote(noteId);
   198→    },
   199→    [setActiveNote]
   200→  );
   201→
   202→  // Handle create note
   203→  const handleCreateNote = useCallback(() => {
   204→    createNote({ folderId: activeFolderId });
   205→  }, [createNote, activeFolderId]);
   206→
   207→  // Handle sidebar width change
   208→  const handleWidthChange = useCallback(
   209→    (width: number) => {
   210→      setNotesLayout({ sidebarWidth: width });
   211→    },
   212→    [setNotesLayout]
   213→  );
   214→
   215→  // Toggle sidebar
   216→  const toggleSidebar = useCallback(() => {
   217→    setIsSidebarCollapsed((prev) => !prev);
   218→  }, []);
   219→
   220→  const childrenVariants = useMemo(
   221→    () => getChildrenVariants(prefersReducedMotion),
   222→    [prefersReducedMotion]
   223→  );
   224→
   225→  // Render folder tree item
   226→  const renderFolderItem = (folder: Folder, depth: number) => {
   227→    const isExpanded = expandedFolders.has(folder.id);
   228→    const childFolders = getChildFolders(folder.id);
   229→    const hasChildren = childFolders.length > 0;
   230→    const isActive = activeFolderId === folder.id;
   231→
   232→    return (
   233→      <div key={folder.id}>
   234→        <div
   235→          className={`group flex items-center gap-1.5 px-2 py-1.5 rounded-md cursor-pointer transition-colors ${
   236→            isActive
   237→              ? 'bg-accent-cyan/10 dark:bg-accent-magenta/10 border-l-2 border-accent-cyan dark:border-accent-magenta'
   238→              : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   239→          }`}
   240→          style={{ paddingLeft: `${depth * 12 + 8}px` }}
   241→          onClick={() => handleSelectFolder(folder.id)}
   242→        >
   243→          {hasChildren ? (
   244→            <button
   245→              onClick={(e) => {
   246→                e.stopPropagation();
   247→                toggleFolder(folder.id);
   248→              }}
   249→              className="text-text-light-tertiary dark:text-text-dark-tertiary"
   250→            >
   251→              {isExpanded ? (
   252→                <ChevronDown className="w-3.5 h-3.5" />
   253→              ) : (
   254→                <ChevronRight className="w-3.5 h-3.5" />
   255→              )}
   256→            </button>
   257→          ) : (
   258→            <span className="w-3.5" />
   259→          )}
   260→
   261→          {isExpanded ? (
   262→            <FolderOpen className="w-4 h-4 text-accent-cyan dark:text-accent-magenta flex-shrink-0" />
   263→          ) : (
   264→            <FolderIcon className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary flex-shrink-0" />
   265→          )}
   266→
   267→          <span
   268→            className={`text-sm truncate flex-1 ${
   269→              isActive
   270→                ? 'font-medium text-accent-cyan dark:text-accent-magenta'
   271→                : 'text-text-light-primary dark:text-text-dark-primary'
   272→            }`}
   273→          >
   274→            {folder.name}
   275→          </span>
   276→        </div>
   277→
   278→        <AnimatePresence initial={false}>
   279→          {isExpanded && hasChildren && (
   280→            <motion.div
   281→              className="overflow-hidden"
   282→              initial="hidden"
   283→              animate="visible"
   284→              exit="hidden"
   285→              variants={childrenVariants}
   286→            >
   287→              {childFolders.map((child) => renderFolderItem(child, depth + 1))}
   288→            </motion.div>
   289→          )}
   290→        </AnimatePresence>
   291→      </div>
   292→    );
   293→  };
   294→
   295→  // Render note item
   296→  const renderNoteItem = (note: Note) => {
   297→    const isActive = activeNoteId === note.id;
   298→
   299→    return (
   300→      <div
   301→        key={note.id}
   302→        className={`group flex items-center gap-2 px-3 py-2 rounded-md cursor-pointer transition-colors ${
   303→          isActive
   304→            ? 'bg-accent-cyan/10 dark:bg-accent-magenta/10 border-l-2 border-accent-cyan dark:border-accent-magenta'
   305→            : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   306→        }`}
   307→        onClick={() => handleSelectNote(note.id)}
   308→      >
   309→        <FileText
   310→          className={`w-4 h-4 flex-shrink-0 ${
   311→            isActive
   312→              ? 'text-accent-cyan dark:text-accent-magenta'
   313→              : 'text-text-light-tertiary dark:text-text-dark-tertiary'
   314→          }`}
   315→        />
   316→        <div className="flex-1 min-w-0">
   317→          <span
   318→            className={`text-sm truncate block ${
   319→              isActive
   320→                ? 'font-medium text-accent-cyan dark:text-accent-magenta'
   321→                : 'text-text-light-primary dark:text-text-dark-primary'
   322→            }`}
   323→          >
   324→            {note.title || 'Untitled'}
   325→          </span>
   326→          <span className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary truncate block">
   327→            {new Date(note.updatedAt).toLocaleDateString()}
   328→          </span>
   329→        </div>
   330→        <div className="flex items-center gap-0.5 flex-shrink-0">
   331→          {note.isPinned && <Pin className="w-3 h-3 text-accent-purple" />}
   332→          {note.isFavorite && (
   333→            <Star className="w-3 h-3 text-accent-yellow fill-accent-yellow" />
   334→          )}
   335→        </div>
   336→      </div>
   337→    );
   338→  };
   339→
   340→  return (
   341→    <div className="flex-1 flex min-h-0 overflow-hidden bg-surface-light dark:bg-surface-dark">
   342→      {/* Sidebar */}
   343→      <AnimatePresence mode="wait">
   344→        {!isSidebarCollapsed && (
   345→          <motion.div
   346→            ref={sidebarRef}
   347→            initial={{ width: 0, opacity: 0 }}
   348→            animate={{ width: Math.max(sidebarWidth, 220), opacity: 1 }}
   349→            exit={{ width: 0, opacity: 0 }}
   350→            transition={{ duration: 0.2, ease: 'easeInOut' }}
   351→            className="flex-shrink-0 flex flex-col min-h-0 min-w-0 border-r border-border-light dark:border-border-dark relative overflow-hidden"
   352→            style={{ width: Math.max(sidebarWidth, 220) }}
   353→          >
   354→            {/* Header with tabs */}
   355→            <div className="flex items-center justify-between px-3 py-2 border-b border-border-light dark:border-border-dark flex-shrink-0">
   356→              <div className="flex items-center gap-1">
   357→                {/* Tab buttons */}
   358→                <button
   359→                  onClick={() => setActiveTab('folders')}
   360→                  className={`px-2 py-1 text-xs font-medium rounded transition-colors ${
   361→                    activeTab === 'folders'
   362→                      ? 'bg-accent-cyan/20 dark:bg-accent-magenta/20 text-accent-cyan dark:text-accent-magenta'
   363→                      : 'text-text-light-tertiary dark:text-text-dark-tertiary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   364→                  }`}
   365→                  title="Browse by folders"
   366→                >
   367→                  <FolderIcon className="w-3.5 h-3.5" />
   368→                </button>
   369→                <button
   370→                  onClick={() => setActiveTab('tags')}
   371→                  className={`px-2 py-1 text-xs font-medium rounded transition-colors ${
   372→                    activeTab === 'tags'
   373→                      ? 'bg-accent-cyan/20 dark:bg-accent-magenta/20 text-accent-cyan dark:text-accent-magenta'
   374→                      : 'text-text-light-tertiary dark:text-text-dark-tertiary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   375→                  }`}
   376→                  title="Browse by tags"
   377→                >
   378→                  <Tag className="w-3.5 h-3.5" />
   379→                </button>
   380→                <button
   381→                  onClick={() => setActiveTab('all')}
   382→                  className={`px-2 py-1 text-xs font-medium rounded transition-colors ${
   383→                    activeTab === 'all'
   384→                      ? 'bg-accent-cyan/20 dark:bg-accent-magenta/20 text-accent-cyan dark:text-accent-magenta'
   385→                      : 'text-text-light-tertiary dark:text-text-dark-tertiary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   386→                  }`}
   387→                  title="All notes"
   388→                >
   389→                  <FileText className="w-3.5 h-3.5" />
   390→                </button>
   391→              </div>
   392→
   393→              <div className="flex items-center gap-1">
   394→                <button
   395→                  onClick={handleCreateNote}
   396→                  className="p-1.5 rounded-md hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
   397→                  title="New note"
   398→                  aria-label="Create new note"
   399→                >
   400→                  <Plus className="w-3.5 h-3.5 text-text-light-tertiary dark:text-text-dark-tertiary" />
   401→                </button>
   402→                {onOpenLayoutSettings && (
   403→                  <button
   404→                    onClick={onOpenLayoutSettings}
   405→                    className="p-1.5 rounded-md hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
   406→                    title="Layout settings"
   407→                    aria-label="Open layout settings"
   408→                  >
   409→                    <Settings2 className="w-3.5 h-3.5 text-text-light-tertiary dark:text-text-dark-tertiary" />
   410→                  </button>
   411→                )}
   412→                <button
   413→                  onClick={toggleSidebar}
   414→                  className="p-1.5 rounded-md hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
   415→                  title="Collapse sidebar"
   416→                  aria-label="Collapse sidebar"
   417→                >
   418→                  <PanelLeftClose className="w-3.5 h-3.5 text-text-light-primary dark:text-text-dark-primary" />
   419→                </button>
   420→              </div>
   421→            </div>
   422→
   423→            {/* Search bar */}
   424→            <div className="px-3 py-2 border-b border-border-light dark:border-border-dark flex-shrink-0">
   425→              <div className="relative">
   426→                <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-text-light-tertiary dark:text-text-dark-tertiary" />
   427→                <input
   428→                  type="text"
   429→                  placeholder="Search notes..."
   430→                  value={searchQuery}
   431→                  onChange={(e) => setSearchQuery(e.target.value)}
   432→                  className="w-full pl-8 pr-3 py-1.5 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-md focus:outline-none focus:ring-1 focus:ring-accent-cyan dark:focus:ring-accent-magenta text-text-light-primary dark:text-text-dark-primary placeholder:text-text-light-tertiary dark:placeholder:text-text-dark-tertiary"
   433→                />
   434→              </div>
   435→            </div>
   436→
   437→            {/* Active tags filter indicator */}
   438→            {activeTags.length > 0 && (
   439→              <div className="px-3 py-2 border-b border-border-light dark:border-border-dark flex-shrink-0">
   440→                <div className="flex flex-wrap gap-1">
   441→                  {activeTags.map((tag) => (
   442→                    <span
   443→                      key={tag}
   444→                      className="inline-flex items-center gap-1 px-2 py-0.5 text-xs rounded-full bg-accent-cyan/20 dark:bg-accent-magenta/20 text-accent-cyan dark:text-accent-magenta"
   445→                    >
   446→                      {tag}
   447→                      <button
   448→                        onClick={() => onRemoveTag(tag)}
   449→                        className="hover:text-accent-red transition-colors"
   450→                        aria-label={`Remove ${tag} filter`}
   451→                      >
   452→                        <X className="w-3 h-3" />
   453→                      </button>
   454→                    </span>
   455→                  ))}
   456→                </div>
   457→              </div>
   458→            )}
   459→
   460→            {/* Tab content */}
   461→            <div className="flex-1 min-h-0 overflow-y-auto py-2">
   462→              {/* Folders tab */}
   463→              {activeTab === 'folders' && (
   464→                <div className="space-y-0.5 px-2">
   465→                  {/* All Notes option */}
   466→                  <div
   467→                    className={`flex items-center gap-2 px-2 py-1.5 rounded-md cursor-pointer transition-colors ${
   468→                      activeFolderId === null
   469→                        ? 'bg-accent-cyan/10 dark:bg-accent-magenta/10 border-l-2 border-accent-cyan dark:border-accent-magenta'
   470→                        : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   471→                    }`}
   472→                    onClick={() => handleSelectFolder(null)}
   473→                  >
   474→                    <FileText
   475→                      className={`w-4 h-4 ${
   476→                        activeFolderId === null
   477→                          ? 'text-accent-cyan dark:text-accent-magenta'
   478→                          : 'text-text-light-tertiary dark:text-text-dark-tertiary'
   479→                      }`}
   480→                    />
   481→                    <span
   482→                      className={`text-sm ${
   483→                        activeFolderId === null
   484→                          ? 'font-medium text-accent-cyan dark:text-accent-magenta'
   485→                          : 'text-text-light-primary dark:text-text-dark-primary'
   486→                      }`}
   487→                    >
   488→                      All Notes
   489→                    </span>
   490→                    <span className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary ml-auto">
   491→                      {notes.length}
   492→                    </span>
   493→                  </div>
   494→
   495→                  {/* Folder tree */}
   496→                  {rootFolders.map((folder) => renderFolderItem(folder, 0))}
   497→                </div>
   498→              )}
   499→
   500→              {/* Tags tab */}
   501→              {activeTab === 'tags' && (
   502→                <div className="space-y-0.5 px-2">
   503→                  {allTags.map((tag) => (
   504→                    <div
   505→                      key={tag}
   506→                      className={`flex items-center gap-2 px-2 py-1.5 rounded-md cursor-pointer transition-colors ${
   507→                        activeTags.includes(tag)
   508→                          ? 'bg-accent-cyan/10 dark:bg-accent-magenta/10 border-l-2 border-accent-cyan dark:border-accent-magenta'
   509→                          : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   510→                      }`}
   511→                      onClick={() => {
   512→                        if (activeTags.includes(tag)) {
   513→                          onRemoveTag(tag);
   514→                        } else {
   515→                          onAddTag(tag);
   516→                        }
   517→                      }}
   518→                    >
   519→                      <Tag
   520→                        className={`w-4 h-4 ${
   521→                          activeTags.includes(tag)
   522→                            ? 'text-accent-cyan dark:text-accent-magenta'
   523→                            : 'text-text-light-tertiary dark:text-text-dark-tertiary'
   524→                        }`}
   525→                      />
   526→                      <span
   527→                        className={`text-sm truncate flex-1 ${
   528→                          activeTags.includes(tag)
   529→                            ? 'font-medium text-accent-cyan dark:text-accent-magenta'
   530→                            : 'text-text-light-primary dark:text-text-dark-primary'
   531→                        }`}
   532→                      >
   533→                        {tag}
   534→                      </span>
   535→                      <span className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary">
   536→                        {tagCounts[tag] || 0}
   537→                      </span>
   538→                    </div>
   539→                  ))}
   540→
   541→                  {allTags.length === 0 && (
