   262→        {activeTab === 'daily' && (
   263→          <div className="flex-1 overflow-auto p-6">
   264→            <DailyNotesCalendar />
   265→          </div>
   266→        )}
   267→
   268→        {/* Notes Tab - Main Notes View */}
   269→        {activeTab === 'notes' && (
   270→          <NotesLayout
   271→            activeTags={activeTags}
   272→            onAddTag={handleAddTag}
   273→            onRemoveTag={handleRemoveTag}
   274→            onClearAllTags={handleClearAllTags}
   275→            onOpenTagManager={() => setShowTagManager(true)}
   276→            onOpenTemplateLibrary={() => setShowTemplateLibrary(true)}
   277→            onOpenExportModal={() => setShowExportModal(true)}
   278→          >
   279→            {activeNoteId ? (
   280→              <NotesEditor noteId={activeNoteId} blockId={blockId} />
   281→            ) : (
   282→              <NotesEditorEmpty />
