   284→          </NotesLayout>
   285→        )}
   286→      </div>
   287→
   288→      {/* Tag Manager Modal */}
   289→      <TagManager isOpen={showTagManager} onClose={() => setShowTagManager(false)} />
   290→
   291→      {/* Template Library Modal */}
   292→      <TemplateLibrary
   293→        isOpen={showTemplateLibrary}
   294→        onClose={() => setShowTemplateLibrary(false)}
   295→        onSelect={handleSelectTemplate}
   296→      />
   297→
   298→      {/* Title Prompt Modal */}
   299→      {showTitlePrompt && selectedTemplate && (
   300→        <PromptDialog
   301→          isOpen={true}
   302→          onClose={handleCancelTitle}
   303→          onConfirm={handleConfirmTitle}
   304→          title="Enter Note Title"
   305→          message={`Create a note from template "${selectedTemplate.name}". Please enter a title:`}
   306→          defaultValue={titleInput}
   307→          placeholder="Note title"
   308→          confirmText="Create Note"
   309→        />
   310→      )}
   311→
   312→      {/* Export Notes Modal */}
   313→      <ExportNotesModal isOpen={showExportModal} onClose={() => setShowExportModal(false)} />
   314→    </PageContent>
   315→  );
   316→};
