     1→/**
     2→ * NotesLayout Component
     3→ *
     4→ * Main layout router for the Notes page.
     5→ * Part of the Notes Page Revolution.
     6→ *
     7→ * Features:
     8→ * - Routes between 3 layout styles based on user preference
     9→ * - Three-column (Apple Notes/Bear style)
    10→ * - File tree (Obsidian/VS Code style)
    11→ * - Tabbed sidebar (Notion style)
    12→ * - Mobile drawer fallback for all layouts
    13→ * - Keyboard shortcuts for layout switching
    14→ */
    15→
    16→import React, { useEffect, useState, useCallback } from 'react';
    17→import { motion, AnimatePresence } from 'framer-motion';
    18→import { Menu, X } from 'lucide-react';
    19→import { useSettingsStore, type NotesLayoutStyle } from '../../stores/useSettingsStore';
    20→import { ThreeColumnLayout } from './ThreeColumnLayout';
    21→import { FileTreeLayout } from './FileTreeLayout';
    22→import { TabbedSidebarLayout } from './TabbedSidebarLayout';
    23→import { LayoutSwitcher } from './LayoutSwitcher';
    24→import { FolderSidebar } from './FolderSidebar';
    25→import { NotesList } from './NotesList';
    26→
    27→export interface NotesLayoutProps {
    28→  /** Content to render in the editor pane */
